public class StringMethods {
    public static void main(String[] args) {
        String s = "  Hello, World!  ";

        // --- Core methods ---
        System.out.println(s.length());            // 17
        System.out.println(s.trim());              // "Hello, World!"
        System.out.println(s.strip());             // Java 11+ unicode-aware trim
        System.out.println(s.toUpperCase());       // "  HELLO, WORLD!  "
        System.out.println(s.toLowerCase());       // "  hello, world!  "
        System.out.println(s.contains("World"));  // true
        System.out.println(s.indexOf("o"));       // 5 (first occurrence)
        System.out.println(s.lastIndexOf("o"));   // 9
        System.out.println(s.charAt(2));           // 'H'
        System.out.println(s.substring(2, 7));    // "Hello"
        System.out.println(s.replace("World", "Java")); // "  Hello, Java!  "
        System.out.println(s.startsWith("  H"));  // true
        System.out.println(s.endsWith("  "));     // true
        System.out.println(s.isEmpty());           // false
        System.out.println("".isEmpty());          // true
        System.out.println("  ".isBlank());        // true (Java 11+)

        // --- Split and Join ---
        String csv = "a,b,c,d";
        String[] parts = csv.split(",");           // ["a","b","c","d"]
        String joined = String.join("-", parts);  // "a-b-c-d"
        System.out.println(joined);

        // --- charAt and comparison ---
        String a = "apple", b = "apple", c = new String("apple");
        System.out.println(a == b);        // true  (same pool reference)
        System.out.println(a == c);        // false (new String = heap object)
        System.out.println(a.equals(c));  // true  (content comparison)
        System.out.println("banana".compareTo("apple")); // positive (b > a)
    }
}

public class StringBuilderDemo {
    public static void main(String[] args) {
        // BAD: O(n²) — creates new String object on each iteration
        String bad = "";
        for (int i = 0; i < 5; i++) {
            bad += i + ", ";  // new String object each time
        }
        System.out.println(bad);

        // GOOD: O(n) — StringBuilder maintains internal char buffer
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < 5; i++) {
            sb.append(i).append(", ");
        }
        // Remove trailing ", "
        sb.setLength(sb.length() - 2);
        System.out.println(sb.toString());  // "0, 1, 2, 3, 4"

        // StringBuilder API
        StringBuilder s = new StringBuilder("Hello");
        s.append(" World");          // "Hello World"
        s.insert(5, ",");            // "Hello, World"
        s.delete(5, 7);              // "Hello World" (delete ", ")
        s.replace(6, 11, "Java");    // "Hello Java"
        s.reverse();                 // "avaJ olleH"
        s.deleteCharAt(0);           // "vaJ olleH"
        System.out.println(s);
        System.out.println("Capacity: " + s.capacity()); // initial 16 + grows
        System.out.println("Length:   " + s.length());
    }
}

public class KMPSearch {
    // Knuth-Morris-Pratt: O(n+m) pattern search
    public static int[] buildLPS(String pattern) {
        int m = pattern.length();
        int[] lps = new int[m];  // lps[i] = length of longest proper prefix=suffix
        int len = 0, i = 1;
        while (i < m) {
            if (pattern.charAt(i) == pattern.charAt(len)) {
                lps[i++] = ++len;
            } else if (len != 0) {
                len = lps[len - 1];  // don't increment i — try shorter prefix
            } else {
                lps[i++] = 0;
            }
        }
        return lps;
    }

    public static int search(String text, String pattern) {
        int n = text.length(), m = pattern.length();
        if (m == 0) return 0;
        int[] lps = buildLPS(pattern);
        int i = 0, j = 0;
        while (i < n) {
            if (text.charAt(i) == pattern.charAt(j)) {
                i++; j++;
            }
            if (j == m) return i - j;  // found at index i-j
            else if (i < n && text.charAt(i) != pattern.charAt(j)) {
                if (j != 0) j = lps[j - 1];
                else i++;
            }
        }
        return -1;
    }

    public static void main(String[] args) {
        System.out.println(search("aaabaaab", "aaab"));  // 0
        System.out.println(search("hello world", "world")); // 6
        System.out.println(search("abc", "xyz"));           // -1
    }
}

